import * as ts from "typescript";
import { findTaggedTemplates } from "lit-analyzer/lib/analyze/parse/tagged-template/find-tagged-templates.js";
import { parseHtmlDocument } from "lit-analyzer/lib/analyze/parse/document/text-document/html-document/parse-html-document.js";

export function extractHtmlWithPositions(code: string) {
  const sourceFile = ts.createSourceFile(
    "temp.ts",
    code,
    ts.ScriptTarget.Latest,
    true
  );

  // 1. Finde alle html`...` Templates
  const templates = findTaggedTemplates(sourceFile, ["html", "raw"]);
  
  if (!Array.isArray(templates)) {
    return [];
  }

  const results: any[] = [];

  // 2. Parse jedes Template mit AST
  templates.forEach((template, templateIndex) => {
    const htmlDoc = parseHtmlDocument(template);
    
    // 3. Extrahiere alle Tags mit Positionen
    const tags: any[] = [];
    
    function extractNode(node: any, depth = 0) {
      tags.push({
        tagName: node.tagName,
        depth: depth,
        position: {
          // Position INNERHALB des html`...` Templates
          start: node.location.start,
          end: node.location.end,
          // Position der Start- und End-Tags
          startTag: {
            start: node.location.startTag.start,
            end: node.location.startTag.end
          },
          endTag: node.location.endTag ? {
            start: node.location.endTag.start,
            end: node.location.endTag.end
          } : null
        },
        attributes: node.attributes.map((attr: any) => ({
          name: attr.name,
          value: attr.assignment?.value,
          position: {
            start: attr.location.start,
            end: attr.location.end
          }
        })),
        // Hole den tatsächlichen HTML-Text
        htmlText: node.document.virtualDocument.text.substring(
          node.location.start,
          node.location.end
        )
      });
      
      // Rekursiv durch Kinder
      if (node.children) {
        node.children.forEach((child: any) => extractNode(child, depth + 1));
      }
    }
    
    htmlDoc.rootNodes.forEach(node => extractNode(node));
    
    results.push({
      templateIndex: templateIndex,
      templateTag: template.tag.getText(),
      // Position des gesamten html`...` im TypeScript-Code
      templatePosition: {
        start: template.getStart(),
        end: template.getEnd()
      },
      // Alle Tags im Template mit ihren Positionen
      tags: tags
    });
  });
  
  return results;
}